data.content:
**MSTest does have these assertions.** They're available in MSTest 3.x+:

### Comparison Assertions

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

### For Your `ScoreCalculator`

Here's how to apply them for boundary testing:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──

    [TestMethod]
    public void CalculatePercentage_AllCorrect_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10));
    }

    [TestMethod]
    public void CalculatePercentage_NoneCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10));
    }

    [TestMethod]
    public void CalculatePercentage_Partial_ReturnsValueInRange()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(70.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundary tests ──

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    public void GetGrade_AtBoundary_ReturnsExpected(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    // ── NormalizeScore ──

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(50, 100));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(101.0, result); // never exceeds cap
    }

    [TestMethod]
    public void NormalizeScore_ResultAlwaysNonNegative()
    {
        double result = _calc.NormalizeScore(0, 100);
        Assert.IsGreaterThan(-1.0, result); // result >= 0
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }
}
```

### Key Takeaways

| Assertion | Use case |
|---|---|
| `Assert.IsGreaterThan(bound, actual)` | Value exceeds a lower bound |
| `Assert.IsLessThan(bound, actual)` | Value stays below an upper bound |
| `Assert.IsInRange(actual, low, high)` | Value falls within a range |
| `Assert.ThrowsExactly<T>(…)` | Guard clauses reject invalid input |

These comparison assertions give much better failure messages than `Assert.IsTrue(x > 0)` — they report the actual vs. expected bound on failure.
